class PIIMaskingHelper:
    """Helper to mask PII data for logging purposes."""

    @staticmethod
    def mask_email(email: str) -> str:
        if not email or "@" not in email:
            return "***"
        local, domain = email.split("@", 1)
        if len(local) <= 2:
            masked_local = "*" * len(local)
        else:
            masked_local = local[0] + "*" * (len(local) - 2) + local[-1]
        return f"{masked_local}@{domain}"

    @staticmethod
    def mask_phone(phone: str) -> str:
        if not phone:
            return "***"
        digits = "".join(c for c in phone if c.isdigit())
        if len(digits) <= 4:
            return "***"
        return "*" * (len(digits) - 4) + digits[-4:]

    @staticmethod
    def mask_address(address: str) -> str:
        if not address:
            return "***"
        parts = address.split(",")
        if len(parts) > 1:
            return "***," + ",".join(parts[-2:])
        return "***"

    @classmethod
    def mask_user_data(cls, user_data: dict) -> dict:
        """Return a copy of user_data with PII fields masked for safe logging."""
        masked = user_data.copy()
        if "email" in masked:
            masked["email"] = cls.mask_email(masked["email"])
        if "phone_number" in masked:
            masked["phone_number"] = cls.mask_phone(masked["phone_number"])
        if "address" in masked:
            if isinstance(masked["address"], dict):
                masked["address"] = {k: "***" for k in masked["address"]}
            else:
                masked["address"] = cls.mask_address(str(masked["address"]))
        if "ssn" in masked:
            masked["ssn"] = "***-**-" + str(masked["ssn"])[-4:] if masked["ssn"] else "***"
        if "date_of_birth" in masked:
            masked["date_of_birth"] = "****-**-**"
        return masked


class UserDataMessage:
    """Represents a user data message containing PII."""

    def __init__(
        self,
        user_id: str,
        email: Optional[str] = None,
        phone_number: Optional[str] = None,
        first_name: Optional[str] = None,
        last_name: Optional[str] = None,
        address: Optional[dict] = None,
        ssn: Optional[str] = None,
        date_of_birth: Optional[str] = None,
        event_type: str = "USER_DATA_UPDATE",
        metadata: Optional[dict] = None,
    ):
        self.message_id = str(uuid.uuid4())
        self.user_id = user_id
        self.email = email
        self.phone_number = phone_number
        self.first_name = first_name
        self.last_name = last_name
        self.address = address
        self.ssn = ssn
        self.date_of_birth = date_of_birth
        self.event_type = event_type
        self.metadata = metadata or {}
        self.timestamp = datetime.utcnow().isoformat() + "Z"

    def to_dict(self) -> dict:
        message = {
            "message_id": self.message_id,
            "event_type": self.event_type,
            "timestamp": self.timestamp,
            "user_id": self.user_id,
            "user_data": {},
            "metadata": self.metadata,
        }
        pii_fields = {
            "email": self.email,
            "phone_number": self.phone_number,
            "first_name": self.first_name,
            "last_name": self.last_name,
            "address": self.address,
            "ssn": self.ssn,
            "date_of_birth": self.date_of_birth,
        }
        for key, value in pii_fields.items():
            if value is not None:
                message["user_data"][key] = value

        return message

    def to_json(self) -> str:
        return json.dumps(self.to_dict())


class SQSUserDataPublisher:
    """
    SQS publisher for user data messages containing PII.

    Supports both standard and FIFO queues.
    Uses server-side encryption (SSE) for PII protection at rest.
    Implements message attributes for filtering without exposing PII.
    """

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        kms_key_id: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        endpoint_url: Optional[str] = None,
    ):
        self.queue_url = queue_url
        self.is_fifo = queue_url.endswith(".fifo")
        self.kms_key_id = kms_key_id
        self.masking_helper = PIIMaskingHelper()

        session_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            session_kwargs["aws_access_key_id"] = aws_access_key_id
            session_kwargs["aws_secret_access_key"] = aws_secret_access_key

        session = boto3.Session(**session_kwargs)

        client_kwargs = {}
        if endpoint_url:
            client_kwargs["endpoint_url"] = endpoint_url

        self.sqs_client = session.client("sqs", **client_kwargs)

        logger.info(
            "SQS UserData Publisher initialized for queue: %s (FIFO: %s)",
            queue_url,
            self.is_fifo,
        )

    def _enable_queue_encryption(self):
        """Enable server-side encryption on the queue for PII protection."""
        try:
            attributes = {}
            if self.kms_key_id:
                attributes["KmsMasterKeyId"] = self.kms_key_id
                attributes["KmsDataKeyReusePeriodSeconds"] = "300"
            else:
                attributes["SqsManagedSseEnabled"] = "true"

            self.sqs_client.set_queue_attributes(
                QueueUrl=self.queue_url, Attributes=attributes
            )
            logger.info("Queue encryption enabled successfully.")
        except ClientError as e:
            logger.error("Failed to enable queue encryption: %s", e)
            raise

    def _build_message_attributes(self, message: UserDataMessage) -> dict:
        """
        Build SQS message attributes for filtering.
        These attributes do NOT contain PII - only metadata for routing/filtering.
        """
        attributes = {
            "EventType": {
                "DataType": "String",
                "StringValue": message.event_type,
            },
            "UserId": {
                "DataType": "String",
                "StringValue": message.user_id,
            },
            "Timestamp": {
                "DataType": "String",
                "StringValue": message.timestamp,
            },
            "ContainsPII": {
                "DataType": "String",
                "StringValue": "true",
            },
        }

        # Indicate which PII fields are present without exposing the values
        pii_fields_present = []
        if message.email:
            pii_fields_present.append("email")
        if message.phone_number:
            pii_fields_present.append("phone_number")
        if message.address:
            pii_fields_present.append("address")
        if message.ssn:
            pii_fields_present.append("ssn")
        if message.date_of_birth:
            pii_fields_present.append("date_of_birth")
        if message.first_name or message.last_name:
            pii_fields_present.append("name")

        if pii_fields_present:
            attributes["PIIFieldsPresent"] = {
                "DataType": "String",
                "StringValue": ",".join(pii_fields_present),
            }

        return attributes

    def publish(
        self,
        message: UserDataMessage,
        message_group_id: Optional[str] = None,
        delay_seconds: int = 0,
    ) -> dict:
        """
        Publish a single user data message to SQS.

        Args:
            message: The UserDataMessage to publish.
            message_group_id: Required for FIFO queues. Defaults to user_id.
            delay_seconds: Delay before message becomes visible (0-900 seconds).

        Returns:
            SQS SendMessage response dict.
        """
        send_kwargs = {
            "QueueUrl": self.queue_url,
            "MessageBody": message.to_json(),
            "MessageAttributes": self._build_message_attributes(message),
            "DelaySeconds": delay_seconds,
        }

        if self.is_fifo:
            send_kwargs["MessageGroupId"] = message_group_id or message.user_id
            send_kwargs["MessageDeduplicationId"] = message.message_id
            # DelaySeconds is not supported per-message on FIFO
            del send_kwargs["DelaySeconds"]

        # Log with masked PII
        masked_data = self.masking_helper.mask_user_data(
            message.to_dict().get("user_data", {})
        )
        logger.info(
            "Publishing user data message: message_id=%s, user_id=%s, event_type=%s, masked_data=%s",
            message.message_id,
            message.user_id,
            message.event_type,
            json.dumps(masked_data),
        )

        try:
            response = self.sqs_client.send_message(**send_kwargs)
            logger.info(
                "Message published successfully: message_id=%s, sqs_message_id=%s",
                message.message_id,
                response.get("MessageId"),
            )
            return response
        except ClientError as e:
            logger.error(
                "Failed to publish message: message_id=%s, user_id=%s, error=%s",
                message.message_id,
                message.user_id,
                e,
            )
            raise

    def publish_batch(
        self,
        messages: list,
        message_group_id: Optional[str] = None,
    ) -> dict:
        """
        Publish a batch of user data messages to SQS (max 10 per batch).

        Args:
            messages: List of UserDataMessage objects (max 10).
            message_group_id: For FIFO queues, shared group ID for the batch.

        Returns:
            SQS SendMessageBatch response dict.
        """
        if len(messages) > 10:
            raise ValueError("SQS batch limit is 10 messages. Got %d." % len(messages))

        entries = []
        for idx, message in enumerate(messages):
            entry = {
                "Id": str(idx),
                "MessageBody": message.to_json(),
                "MessageAttributes": self._build_message_attributes(message),
            }
            if not self.is_fifo:
                entry["DelaySeconds"] = 0

            if self.is_fifo:
                entry["MessageGroupId"] = message_group_id or message.user_id
                entry["MessageDeduplicationId"] = message.message_id

            entries.append(entry)

            masked_data = self.masking_helper.mask_user_data(
                message.to_dict().get("user_data", {})
            )
            logger.info(
                "Batch entry %d: message_id=%s, user_id=%s, masked_data=%s",
                idx,
                message.message_id,
                message.user_id,
                json.dumps(masked_data),
            )

        try:
            response = self.sqs_client.send_message_batch(
                QueueUrl=self.queue_url, Entries=entries
            )

            successful = response.get("Successful", [])
            failed = response.get("Failed", [])

            logger.info(
                "Batch publish result: %d successful, %d failed",
                len(successful),
                len(failed),
            )

            if failed:
                for failure in failed:
                    logger.error(
                        "Failed batch entry: Id=%s, Code=%s, Message=%s",
                        failure.get("Id"),
                        failure.get("Code"),
                        failure.get("Message"),
                    )

            return response
        except ClientError as e:
            logger.error("Failed to publish batch: %s", e)
            raise

    def publish_large_batch(
        self,
        messages: list,
        message_group_id: Optional[str] = None,
    ) -> list:
        """
        Publish any number of messages by splitting into batches of 10.

        Returns:
            List of SQS SendMessageBatch response dicts.
        """
        responses = []
        for i in range(0, len(messages), 10):
            batch = messages[i : i + 10]
            response = self.publish_batch(batch, message_group_id=message_group_id)
            responses.append(response)
        return responses


